#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

inline int maximum(int a, int b, int c) {
    int k = (b >= a) ? b : a;
    return (c >= k) ? c : k;
}

__kernel void nw_kernel1(__global int* reference,
                         __global int* input_itemsets,
                         __global int* output_itemsets,
                         __local int* input_itemsets_l,
                         __local int* reference_l,
                         int max_cols,
                         int penalty,
                         int blk,
                         int block_width,
                         int worksize,
                         int offset_r,
                         int offset_c) {
    (void)output_itemsets;
    (void)block_width;
    (void)worksize;

    int tx = get_local_id(0);
    if (tx != 0) return;

    int b_index = get_group_id(0);
    int b_index_x = blk - 1 - b_index;
    int b_index_y = b_index;

    int row_base = b_index_x * BLOCK_SIZE + offset_r;
    int col_base = b_index_y * BLOCK_SIZE + offset_c;

    for (int i = 0; i < BLOCK_SIZE; i++) {
        for (int j = 0; j < BLOCK_SIZE; j++) {
            reference_l[i * BLOCK_SIZE + j] =
                reference[max_cols * (row_base + i + 1) + (col_base + j + 1)];
        }
    }

    for (int i = 0; i < BLOCK_SIZE + 1; i++) {
        for (int j = 0; j < BLOCK_SIZE + 1; j++) {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] =
                input_itemsets[max_cols * (row_base + i) + (col_base + j)];
        }
    }

    for (int i = 1; i < BLOCK_SIZE + 1; i++) {
        for (int j = 1; j < BLOCK_SIZE + 1; j++) {
            int nw = input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + (j - 1)] +
                     reference_l[(i - 1) * BLOCK_SIZE + (j - 1)];
            int w  = input_itemsets_l[i * (BLOCK_SIZE + 1) + (j - 1)] - penalty;
            int n  = input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty;
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = maximum(nw, w, n);
        }
    }

    for (int i = 0; i < BLOCK_SIZE; i++) {
        for (int j = 0; j < BLOCK_SIZE; j++) {
            input_itemsets[max_cols * (row_base + i + 1) + (col_base + j + 1)] =
                input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + (j + 1)];
        }
    }
}

